@Service
public class SamlService {

    private static final Logger logger = LoggerFactory.getLogger(SamlService.class);

    private final SamlConfig samlConfig;
    private final KeystoreService keystoreService;
    private final RandomIdentifierGenerationStrategy idGenerator = new RandomIdentifierGenerationStrategy();

    public SamlService(SamlConfig samlConfig, KeystoreService keystoreService) {
        this.samlConfig = samlConfig;
        this.keystoreService = keystoreService;
    }

    @SuppressWarnings("unchecked")
    private <T extends XMLObject> T buildSamlObject(QName qName) {
        XMLObjectBuilderFactory builderFactory = XMLObjectProviderRegistrySupport.getBuilderFactory();
        return (T) builderFactory.getBuilder(qName).buildObject(qName);
    }

    public AuthnRequest buildAuthnRequest() throws Exception {
        AuthnRequest authnRequest = buildSamlObject(AuthnRequest.DEFAULT_ELEMENT_NAME);
        authnRequest.setID("_" + idGenerator.generateIdentifier());
        authnRequest.setIssueInstant(Instant.now());
        authnRequest.setDestination(samlConfig.getIdp().getSsoUrl());
        authnRequest.setProtocolBinding("urn:oasis:names:tc:SAML:2.0:bindings:HTTP-POST");
        authnRequest.setAssertionConsumerServiceURL(samlConfig.getAcsUrl());
        authnRequest.setVersion(SAMLVersion.VERSION_20);
        authnRequest.setForceAuthn(false);
        authnRequest.setIsPassive(false);

        // Issuer
        Issuer issuer = buildSamlObject(Issuer.DEFAULT_ELEMENT_NAME);
        issuer.setValue(samlConfig.getEntityId());
        authnRequest.setIssuer(issuer);

        // NameIDPolicy
        NameIDPolicy nameIDPolicy = buildSamlObject(NameIDPolicy.DEFAULT_ELEMENT_NAME);
        nameIDPolicy.setFormat("urn:oasis:names:tc:SAML:1.1:nameid-format:emailAddress");
        nameIDPolicy.setAllowCreate(true);
        authnRequest.setNameIDPolicy(nameIDPolicy);

        // RequestedAuthnContext
        RequestedAuthnContext requestedAuthnContext = buildSamlObject(RequestedAuthnContext.DEFAULT_ELEMENT_NAME);
        requestedAuthnContext.setComparison(AuthnContextComparisonTypeEnumeration.MINIMUM);

        AuthnContextClassRef authnContextClassRef = buildSamlObject(AuthnContextClassRef.DEFAULT_ELEMENT_NAME);
        authnContextClassRef.setURI("urn:oasis:names:tc:SAML:2.0:ac:classes:PasswordProtectedTransport");
        requestedAuthnContext.getAuthnContextClassRefs().add(authnContextClassRef);
        authnRequest.setRequestedAuthnContext(requestedAuthnContext);

        // Sign the request
        signSamlObject(authnRequest);

        return authnRequest;
    }

    public LogoutRequest buildLogoutRequest(String nameId, String sessionIndex) throws Exception {
        LogoutRequest logoutRequest = buildSamlObject(LogoutRequest.DEFAULT_ELEMENT_NAME);
        logoutRequest.setID("_" + idGenerator.generateIdentifier());
        logoutRequest.setIssueInstant(Instant.now());
        logoutRequest.setDestination(samlConfig.getIdp().getSloUrl());
        logoutRequest.setVersion(SAMLVersion.VERSION_20);

        Issuer issuer = buildSamlObject(Issuer.DEFAULT_ELEMENT_NAME);
        issuer.setValue(samlConfig.getEntityId());
        logoutRequest.setIssuer(issuer);

        NameID nameID = buildSamlObject(NameID.DEFAULT_ELEMENT_NAME);
        nameID.setValue(nameId);
        nameID.setFormat("urn:oasis:names:tc:SAML:1.1:nameid-format:emailAddress");
        logoutRequest.setNameID(nameID);

        if (sessionIndex != null) {
            SessionIndex si = buildSamlObject(SessionIndex.DEFAULT_ELEMENT_NAME);
            si.setValue(sessionIndex);
            logoutRequest.getSessionIndexes().add(si);
        }

        signSamlObject(logoutRequest);

        return logoutRequest;
    }

    private void signSamlObject(AuthnRequest authnRequest) throws Exception {
        Credential credential = keystoreService.getSpCredential();

        Signature signature = buildSamlObject(Signature.DEFAULT_ELEMENT_NAME);
        signature.setSigningCredential(credential);
        signature.setSignatureAlgorithm(SignatureConstants.ALGO_ID_SIGNATURE_RSA_SHA256);
        signature.setCanonicalizationAlgorithm(SignatureConstants.ALGO_ID_C14N_EXCL_OMIT_COMMENTS);

        authnRequest.setSignature(signature);

        MarshallerFactory marshallerFactory = XMLObjectProviderRegistrySupport.getMarshallerFactory();
        Marshaller marshaller = marshallerFactory.getMarshaller(authnRequest);
        marshaller.marshall(authnRequest);

        Signer.signObject(signature);
    }

    private void signSamlObject(LogoutRequest logoutRequest) throws Exception {
        Credential credential = keystoreService.getSpCredential();

        Signature signature = buildSamlObject(Signature.DEFAULT_ELEMENT_NAME);
        signature.setSigningCredential(credential);
        signature.setSignatureAlgorithm(SignatureConstants.ALGO_ID_SIGNATURE_RSA_SHA256);
        signature.setCanonicalizationAlgorithm(SignatureConstants.ALGO_ID_C14N_EXCL_OMIT_COMMENTS);

        logoutRequest.setSignature(signature);

        MarshallerFactory marshallerFactory = XMLObjectProviderRegistrySupport.getMarshallerFactory();
        Marshaller marshaller = marshallerFactory.getMarshaller(logoutRequest);
        marshaller.marshall(logoutRequest);

        Signer.signObject(signature);
    }

    public String marshalToString(XMLObject xmlObject) throws Exception {
        MarshallerFactory marshallerFactory = XMLObjectProviderRegistrySupport.getMarshallerFactory();
        Marshaller marshaller = marshallerFactory.getMarshaller(xmlObject);
        Element element = marshaller.marshall(xmlObject);

        TransformerFactory tf = TransformerFactory.newInstance();
        Transformer transformer = tf.newTransformer();
        StringWriter writer = new StringWriter();
        transformer.transform(new DOMSource(element), new StreamResult(writer));
        return writer.toString();
    }

    public String encodeAuthnRequest(AuthnRequest authnRequest) throws Exception {
        String xml = marshalToString(authnRequest);
        return Base64.getEncoder().encodeToString(xml.getBytes("UTF-8"));
    }

    public String encodeLogoutRequest(LogoutRequest logoutRequest) throws Exception {
        String xml = marshalToString(logoutRequest);
        return Base64.getEncoder().encodeToString(xml.getBytes("UTF-8"));
    }

    public Response parseResponse(String samlResponseBase64) throws Exception {
        byte[] decodedBytes = Base64.getDecoder().decode(samlResponseBase64);
        ByteArrayInputStream is = new ByteArrayInputStream(decodedBytes);

        Document document = OpenSamlUtils.getParserPool().parse(is);
        Element element = document.getDocumentElement();

        UnmarshallerFactory unmarshallerFactory = XMLObjectProviderRegistrySupport.getUnmarshallerFactory();
        Unmarshaller unmarshaller = unmarshallerFactory.getUnmarshaller(element);

        return (Response) unmarshaller.unmarshall(element);
    }

    public SamlPrincipal validateAndExtract(Response response) throws Exception {
        // Validate status
        StatusCode statusCode = response.getStatus().getStatusCode();
        if (!StatusCode.SUCCESS.equals(statusCode.getValue())) {
            throw new SecurityException("SAML Response status is not success: " + statusCode.getValue());
        }

        // Validate issuer
        if (response.getIssuer() != null) {
            String issuer = response.getIssuer().getValue();
            if (!samlConfig.getIdp().getEntityId().equals(issuer)) {
                throw new SecurityException("Invalid issuer: " + issuer);
            }
        }

        // Validate destination
        if (response.getDestination() != null && !samlConfig.getAcsUrl().equals(response.getDestination())) {
            throw new SecurityException("Invalid destination: " + response.getDestination());
        }

        // Validate signature on response
        if (response.getSignature() != null) {
            SignatureValidator.validate(response.getSignature(), keystoreService.getIdpCredential());
        }

        // Get assertion
        List<Assertion> assertions = response.getAssertions();
        if (assertions == null || assertions.isEmpty()) {
            throw new SecurityException("No assertions found in SAML response");
        }

        Assertion assertion = assertions.get(0);

        // Validate assertion signature
        if (assertion.getSignature() != null) {
            SignatureValidator.validate(assertion.getSignature(), keystoreService.getIdpCredential());
        }

        // Validate conditions
        validateConditions(assertion.getConditions());

        // Extract NameID
        String nameId = null;
        if (assertion.getSubject() != null && assertion.getSubject().getNameID() != null) {
            nameId = assertion.getSubject().getNameID().getValue();
        }

        // Extract session index
        String sessionIndex = null;
        if (!assertion.getAuthnStatements().isEmpty()) {
            sessionIndex = assertion.getAuthnStatements().get(0).getSessionIndex();
        }

        // Extract attributes
        Map<String, List<String>> attributes = new HashMap<>();
        for (AttributeStatement attrStatement : assertion.getAttributeStatements()) {
            for (Attribute attribute : attrStatement.getAttributes()) {
                String attrName = attribute.getName();
                List<String> values = new ArrayList<>();
                for (XMLObject xmlObject : attribute.getAttributeValues()) {
                    if (xmlObject instanceof XSString) {
                        values.add(((XSString) xmlObject).getValue());
                    } else {
                        values.add(xmlObject.getDOM().getTextContent());
                    }
                }
                attributes.put(attrName, values);
            }
        }

        logger.info("SAML SSO authentication successful for user: {}", nameId);
        return new SamlPrincipal(nameId, sessionIndex, attributes);
    }

    private void validateConditions(Conditions conditions) throws SecurityException {
        if (conditions == null) return;

        Instant now = Instant.now();

        if (conditions.getNotBefore() != null && now.isBefore(conditions.getNotBefore())) {
            throw new SecurityException("SAML assertion is not yet valid");
        }

        if (conditions.getNotOnOrAfter() != null && now.isAfter(conditions.getNotOnOrAfter())) {
            throw new SecurityException("SAML assertion has expired");
        }

        // Validate audience restriction
        for (AudienceRestriction audienceRestriction : conditions.getAudienceRestrictions()) {
            boolean validAudience = false;
            for (Audience audience : audienceRestriction.getAudiences()) {
                if (samlConfig.getEntityId().equals(audience.getURI())) {
                    validAudience = true;
                    break;
                }
            }
            if (!validAudience) {
                throw new SecurityException("SP is not a valid audience for this assertion");
            }
        }
    }
}

