package com.example.samlsp.service;

import org.springframework.stereotype.Service;

import java.util.Map;
import java.util.concurrent.ConcurrentHashMap;

@Service
public class SamlSessionService {

    private final Map<String, String> requestIdStore = new ConcurrentHashMap<>();

    public void storeRequestId(String requestId, String relayState) {
        requestIdStore.put(requestId, relayState);
    }

    public String getRelayState(String requestId) {
        return requestIdStore.remove(requestId);
    }

    public boolean isValidRequestId(String requestId) {
        return requestIdStore.containsKey(requestId);
    }
}

// ============================================================
// controller/SamlController.java
// ============================================================
package com.example.samlsp.controller;

import com.example.samlsp.config.SamlConfig;
import com.example.samlsp.model.SamlAuthenticationToken;
import com.example.samlsp.model.SamlPrincipal;
import com.example.samlsp.service.SamlMetadataService;
import com.example.samlsp.service.SamlService;
import com.example.samlsp.service.SamlSessionService;
import org.opensaml.saml.saml2.core.AuthnRequest;
import org.opensaml.saml.saml2.core.LogoutRequest;
import org.opensaml.saml.saml2.core.Response;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.http.MediaType;
import org.springframework.security.core.Authentication;
import org.springframework.security.core.context.SecurityContextHolder;
import org.springframework.stereotype.Controller;
import org.springframework.ui.Model;
import org.springframework.web.bind.annotation.*;

import javax.servlet.http.HttpServletRequest;
import javax.servlet.http.HttpServletResponse;
import javax.servlet.http.HttpSession;

@Controller
public class SamlController {

    private static final Logger logger = LoggerFactory.getLogger(SamlController.class);

    private final SamlConfig samlConfig;
    private final SamlService samlService;
    private final SamlMetadataService samlMetadataService;
    private final SamlSessionService samlSessionService;

    public SamlController(SamlConfig samlConfig, SamlService samlService,
                          SamlMetadataService samlMetadataService, SamlSessionService samlSessionService) {
        this.samlConfig = samlConfig;
        this.samlService = samlService;
        this.samlMetadataService = samlMetadataService;
        this.samlSessionService = samlSessionService;
    }

    @GetMapping(value = "/saml/metadata", produces = MediaType.APPLICATION_XML_VALUE)
    @ResponseBody
    public String metadata() throws Exception {
        return samlMetadataService.generateMetadata();
    }

    @GetMapping("/saml/login")
    public String initiateLogin(Model model, HttpServletRequest request) throws Exception {
        AuthnRequest authnRequest = samlService.buildAuthnRequest();

        String requestId = authnRequest.getID();
        String relayState = request.getParameter("returnTo");
        if (relayState == null) relayState = "/dashboard";
        samlSessionService.storeRequestId(requestId, relayState);

        String encodedRequest = samlService.encodeAuthnRequest(authnRequest);

        model.addAttribute("samlRequest", encodedRequest);
        model.addAttribute("idpSsoUrl", samlConfig.getIdp().getSsoUrl());
        model.addAttribute("relayState", relayState);

        return "saml-post-form";
    }

    @PostMapping("/saml/acs")
    public String assertionConsumerService(
            @RequestParam("SAMLResponse") String samlResponseBase64,
            @RequestParam(value = "RelayState", required = false) String relayState,
            HttpServletRequest request) throws Exception {

        logger.info("Received SAML response at ACS endpoint");

        try {
            Response response = samlService.parseResponse(samlResponseBase64);
            SamlPrincipal principal = samlService.validateAndExtract(response);

            SamlAuthenticationToken authToken = new SamlAuthenticationToken(principal);
            SecurityContextHolder.getContext().setAuthentication(authToken);

            HttpSession session = request.getSession(true);
            session.setAttribute("SPRING_SECURITY_CONTEXT", SecurityContextHolder.getContext());
            session.setAttribute("samlPrincipal", principal);

            logger.info("User {} authenticated successfully via SAML SSO", principal.getNameId());

            String redirectUrl = (relayState != null && !relayState.isEmpty()) ? relayState : "/dashboard";
            return "redirect:" + redirectUrl;

        } catch (Exception e) {
            logger.error("SAML authentication failed", e);
            return "redirect:/saml/error?message=" + e.getMessage();
        }
    }

    @GetMapping("/saml/logout")
    public String initiateLogout(Model model, HttpServletRequest request) throws Exception {
        Authentication auth = SecurityContextHolder.getContext().getAuthentication();
        if (auth == null || !(auth.getPrincipal() instanceof SamlPrincipal)) {
            return "redirect:/";
        }

        SamlPrincipal principal = (SamlPrincipal) auth.getPrincipal();
        LogoutRequest logoutRequest = samlService.buildLogoutRequest(
                principal.getNameId(), principal.getSessionIndex()
        );

        String encodedRequest = samlService.encodeLogoutRequest(logoutRequest);

        // Clear local session
        SecurityContextHolder.clearContext();
        HttpSession session = request.getSession(false);
        if (session != null) {
            session.invalidate();
        }

        model.addAttribute("samlRequest", encodedRequest);
        model.addAttribute("idpSloUrl", samlConfig.getIdp().getSloUrl());

        return "saml-logout-form";
    }

    @PostMapping("/saml/slo")
    public String singleLogoutCallback(
            @RequestParam(value = "SAMLResponse", required = false) String samlResponse,
            HttpServletRequest request) {

        logger.info("SLO callback received");

        SecurityContextHolder.clearContext();
        HttpSession session = request.getSession(false);
        if (session != null) {
            session.invalidate();
        }

        return "redirect:/?logout=true";
    }

    @GetMapping("/saml/error")
    public String samlError(@RequestParam(value = "message", required = false) String message, Model model) {
        model.addAttribute("errorMessage", message != null ? message : "SAML authentication error");
        return "saml-error";
    }
}

