// controller/DashboardController.java
// ============================================================
package com.example.samlsp.controller;

import com.example.samlsp.model.SamlPrincipal;
import org.springframework.security.core.Authentication;
import org.springframework.security.core.context.SecurityContextHolder;
import org.springframework.stereotype.Controller;
import org.springframework.ui.Model;
import org.springframework.web.bind.annotation.GetMapping;

@Controller
public class DashboardController {

    @GetMapping("/")
    public String home() {
        Authentication auth = SecurityContextHolder.getContext().getAuthentication();
        if (auth != null && auth.getPrincipal() instanceof SamlPrincipal) {
            return "redirect:/dashboard";
        }
        return "home";
    }

    @GetMapping("/dashboard")
    public String dashboard(Model model) {
        Authentication auth = SecurityContextHolder.getContext().getAuthentication();
        if (auth != null && auth.getPrincipal() instanceof SamlPrincipal) {
            SamlPrincipal principal = (SamlPrincipal) auth.getPrincipal();
            model.addAttribute("user", principal);
            model.addAttribute("nameId", principal.getNameId());
            model.addAttribute("attributes", principal.getAttributes());
            model.addAttribute("email", principal.getAttribute("email"));
            model.addAttribute("firstName", principal.getAttribute("firstName"));
            model.addAttribute("lastName", principal.getAttribute("lastName"));
        }
        return "dashboard";
    }

    @GetMapping("/profile")
    public String profile(Model model) {
        Authentication auth = SecurityContextHolder.getContext().getAuthentication();
        if (auth != null && auth.getPrincipal() instanceof SamlPrincipal) {
            SamlPrincipal principal = (SamlPrincipal) auth.getPrincipal();
            model.addAttribute("user", principal);
        }
        return "profile";
    }
}

// ============================================================
// config/SecurityConfig.java
// ============================================================
package com.example.samlsp.config;

import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import org.springframework.security.config.annotation.web.builders.HttpSecurity;
import org.springframework.security.config.annotation.web.configuration.EnableWebSecurity;
import org.springframework.security.web.SecurityFilterChain;
import org.springframework.security.web.authentication.www.BasicAuthenticationFilter;

@Configuration
@EnableWebSecurity
public class SecurityConfig {

    @Bean
    public SecurityFilterChain filterChain(HttpSecurity http) throws Exception {
        http
                .csrf(csrf -> csrf
                        .ignoringAntMatchers("/saml/acs", "/saml/slo")
                )
                .authorizeRequests(auth -> auth
                        .antMatchers("/", "/saml/**", "/error", "/css/**", "/js/**", "/images/**").permitAll()
                        .antMatchers("/dashboard", "/profile").authenticated()
                        .anyRequest().authenticated()
                )
                .formLogin().disable()
                .httpBasic().disable()
                .exceptionHandling(ex -> ex
                        .authenticationEntryPoint((request, response, authException) -> {
                            response.sendRedirect("/saml/login");
                        })
                )
                .logout(logout -> logout
                        .logoutUrl("/logout")
                        .logoutSuccessUrl("/")
                        .invalidateHttpSession(true)
                        .clearAuthentication(true)
                );

        return http.build();
    }
}

