// ============================================================
package com.example.samlsp.exception;

public class SamlException extends RuntimeException {

    public SamlException(String message) {
        super(message);
    }

    public SamlException(String message, Throwable cause) {
        super(message, cause);
    }
}

// ============================================================
// exception/GlobalExceptionHandler.java
// ============================================================
package com.example.samlsp.exception;

import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.ui.Model;
import org.springframework.web.bind.annotation.ControllerAdvice;
import org.springframework.web.bind.annotation.ExceptionHandler;

@ControllerAdvice
public class GlobalExceptionHandler {

    private static final Logger logger = LoggerFactory.getLogger(GlobalExceptionHandler.class);

    @ExceptionHandler(SamlException.class)
    public String handleSamlException(SamlException ex, Model model) {
        logger.error("SAML error: {}", ex.getMessage(), ex);
        model.addAttribute("errorMessage", ex.getMessage());
        return "saml-error";
    }

    @ExceptionHandler(Exception.class)
    public String handleGenericException(Exception ex, Model model) {
        logger.error("Unexpected error: {}", ex.getMessage(), ex);
        model.addAttribute("errorMessage", "An unexpected error occurred");
        return "error";
    }
}

